data: {"backend_uuid": "00000000-0000-0000-0000-000000000001", "context_uuid": "00000000-0000-0000-0000-000000000001", "uuid": "00000000-0000-0000-0000-000000000001", "frontend_context_uuid": "00000000-0000-0000-0000-000000000001", "frontend_uuid": "00000000-0000-0000-0000-000000000001", "text": "[{\"step_type\": \"INITIAL_QUERY\", \"content\": {\"goal_id\": null, \"query\": \"\\\"Default friendly, but shit can get number ten, Messi.\\\"\"}, \"uuid\": \"\"}, {\"step_type\": \"SEARCH_WEB\", \"content\": {\"goal_id\": \"0\", \"queries\": [{\"engine\": \"web\", \"query\": \"Messi number ten\", \"limit\": 8}]}, \"uuid\": \"00000000-0000-0000-0000-000000000001\"}, {\"step_type\": \"SEARCH_RESULTS\", \"content\": {\"goal_id\": \"0\", \"web_results\": [{\"name\": \"Lionel Messi - Wikipedia\", \"url\": \"https://en.wikipedia.org/wiki/Lionel_Messi\", \"snippet\": \"\", \"is_attachment\": false, \"is_navigational\": false, \"is_focused_web\": false, \"is_memory\": false, \"is_conversation_history\": false, \"is_conversation_summary\": false, \"tab_id\": null, \"meta_data\": {\"client\": \"web\", \"date\": \"2005-07-01\", \"domain_name\": \"Wikimedia Foundation, Inc.\", \"published_date\": \"2005-07-01T00:00:00\"}, \"sitelinks\": null, \"trust\": null}, {\"name\": \"Mirror - song and lyrics by Samiyam, Earl Sweatshirt | Spotify\", \"url\": \"https://open.spotify.com/track/6i9MvKM6OXpRY9E1XvOLXM\", \"snippet\": \"Default friendly, but shit can get number ten, Messi. We cop Henny, you grab a bench and you warm it up. 21 'fore I step myself and my horses up. Devil at the\\u00a0...\", \"is_attachment\": false, \"is_navigational\": false, \"is_focused_web\": false, \"is_memory\": false, \"is_conversation_history\": false, \"is_conversation_summary\": false, \"tab_id\": null, \"meta_data\": {\"client\": \"web\", \"citation_domain_name\": \"open.spotify\", \"suffix\": \"com\"}, \"sitelinks\": null, \"trust\": null}, {\"name\": \"#MESSI10 | A decade of Messi as Bar\\u00e7a's no.10\", \"url\": \"https://www.youtube.com/watch?v=_WdLNL4l4kc\", \"snippet\": \"On 24 July 2008, one of the most emblematic associations in FC Barcelona history was born. It occured in a preseason friendly against Scottish side Hibernian: Just one week before, club legend Ronaldinho Ga\\u00facho had departed the club to sign for AC Milan. That freed up the number 10 shirt, and it was Leo Messi who wore it for the first time in the summer fixture.\\n\\nIn that game, won 6-0 by Bar\\u00e7a, Messi scored the second goal. It did not count towards his official tally for the club, but was nevertheless a terrific strike typical of the Argentine.\\n\\nTen days later, it was official\\nA short time later, on 3 August, it was announced that Messi would be FC Barcelona's number 10 for the 2008/09 season. His first LaLiga game with the shirt number came on the final day of the month, in Bar\\u00e7a's LaLiga opener against Numancia at Los Pajaritos. Since then, Messi and the number 10 have been a constant for the club.\\n----\\nFC Barcelona on Social Media\\nSubscribe to our official channel http://www.youtube.com/subscription_center?add_user=fcbarcelona\\nSite: http://www.fcbarcelona.com\\nFacebook: http://www.facebook.com/fcbarcelona\\nInstagram: http://www.instagram.com\\nTwitter: http://twitter.com/FCBarcelona\\nGoogle+: http://plus.google.com/+FCBarcelona\\nViber: http://chats.viber.com/fcbarcelona\", \"is_attachment\": false, \"is_navigational\": false, \"is_focused_web\": false, \"is_memory\": false, \"is_conversation_history\": false, \"is_conversation_summary\": false, \"tab_id\": null, \"meta_data\": {\"client\": \"web\", \"date\": \"2018-07-23\", \"domain_name\": \"youtube\", \"description\": \"On 24 July 2008, one of the most emblematic associations in FC Barcelona history was born. It occured in a preseason friendly against Scottish side Hibernian: Just one week before, club legend Ronaldinho Ga\\u00facho had departed the club to sign for AC Milan. That freed up the number 10 shirt, and it was Leo Messi who wore it for the first time in the summer fixture.\\n\\nIn that game, won 6-0 by Bar\\u00e7a, Messi scored the second goal. It did not count towards his official tally for the club, but was nevertheless a terrific strike typical of the Argentine.\\n\\nTen days later, it was official\\nA short time later, on 3 August, it was announced that Messi would be FC Barcelona's number 10 for the 2008/09 season. His first LaLiga game with the shirt number came on the final day of the month, in Bar\\u00e7a's LaLiga opener against Numancia at Los Pajaritos. Since then, Messi and the number 10 have been a constant for the club.\\n----\\nFC Barcelona on Social Media\\nSubscribe to our official channel http://www.youtube.com/subscription_center?add_user=fcbarcelona\\nSite: http://www.fcbarcelona.com\\nFacebook: http://www.facebook.com/fcbarcelona\\nInstagram: http://www.instagram.com\\nTwitter: http://twitter.com/FCBarcelona\\nGoogle+: http://plus.google.com/+FCBarcelona\\nViber: http://chats.viber.com/fcbarcelona\", \"published_date\": \"2018-07-23T00:00:00\"}, \"sitelinks\": null, \"trust\": null}, {\"name\": \"Lionel Messi - Squad number history\", \"url\": \"https://www.transfermarkt.com/lionel-messi/rueckennummern/spieler/28003\", \"snippet\": \"This is the shirt number history of Lionel Messi from Inter Miami CF. This statistic shows which shirt numbers the palyer has already worn in his career.\", \"is_attachment\": false, \"is_navigational\": false, \"is_focused_web\": false, \"is_memory\": false, \"is_conversation_history\": false, \"is_conversation_summary\": false, \"tab_id\": null, \"meta_data\": {\"client\": \"web\", \"date\": \"2024-01-01\", \"domain_name\": \"transfermarkt.com\", \"description\": \"This is the shirt number history of Lionel Messi from Inter Miami CF. This statistic shows which shirt numbers the palyer has already worn in his career.\", \"published_date\": \"2024-01-01T00:00:00\"}, \"sitelinks\": null, \"trust\": nul